import { useEffect, useState } from "react";
import { Link } from "react-router-dom";

export default function Dashboard() {
  const [incidents, setIncidents] = useState([]);

  // Fetch data
  const fetchData = async () => {
    const res = await fetch("http://localhost:8000/incidents");
    const data = await res.json();
    setIncidents(data);
  };

  // Auto refresh
  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 3000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={page}>
      <h2>IT Incident Dashboard</h2>

      <div style={grid}>
        {incidents.map((i) => (
          <div
            key={i.id}
            style={card}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = "translateY(-3px)";
              e.currentTarget.style.boxShadow = "0 6px 16px rgba(0,0,0,0.12)";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = "none";
              e.currentTarget.style.boxShadow = "0 4px 12px rgba(0,0,0,0.08)";
            }}
          >
            <h3>{i.component_id}</h3>

            <p>Incident ID: {i.id}</p>

            {/* STATUS BADGE */}
            <span style={statusBadge(i.status)}>
              {i.status}
            </span>

            <p>Severity: {i.severity}</p>
            <p>Signals: {i.signal_count}</p>

            <p>
              Start:{" "}
              {i.start_time
                ? new Date(i.start_time).toLocaleString()
                : "-"}
            </p>

            <Link to={`/incident/${i.id}`}>
              <button style={btn}>View Details</button>
            </Link>
          </div>
        ))}
      </div>
    </div>
  );
}

//
// 🎨 STYLES
//

// ✅ (5) Improved page background
const page = {
  background: "#f5f7fa",
  minHeight: "100vh",
  padding: "25px",
  fontFamily: "Segoe UI"
};

// Grid layout (unchanged)
const grid = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fit, minmax(250px, 1fr))",
  gap: "20px"
};

// ✅ (1) Improved card style
const card = {
  background: "#ffffff",
  padding: "18px",
  borderRadius: "12px",
  boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
  transition: "0.2s ease",
};

// Button (unchanged)
const btn = {
  marginTop: "10px",
  padding: "6px 10px",
  background: "#2f6fed",
  color: "#fff",
  border: "none",
  borderRadius: "6px",
  cursor: "pointer"
};

// ✅ (4) Status badge
const statusBadge = (status) => ({
  display: "inline-block",
  padding: "4px 10px",
  borderRadius: "12px",
  fontSize: "12px",
  marginBottom: "8px",
  background: status === "OPEN" ? "#e3f2fd" : "#e8f5e9",
  color: status === "OPEN" ? "#1976d2" : "#2e7d32"
});
